import assert from "node:assert/strict";
import fs from "node:fs/promises";
import os from "node:os";
import path from "node:path";
import test from "node:test";

import { loadApiConfig } from "@docomator/config";

import { buildApp } from "./app.js";

test("health endpoint reports the API service", async () => {
  const dataDir = await fs.mkdtemp(path.join(os.tmpdir(), "docomator-api-"));
  const app = buildApp(
    loadApiConfig({
      DOCOMATOR_DATA_DIR: dataDir,
      DOCOMATOR_VERSION: "test-version",
      DOCOMATOR_LOG_LEVEL: "fatal"
    })
  );

  const response = await app.inject({ method: "GET", url: "/healthz" });
  assert.equal(response.statusCode, 200);
  assert.equal(response.json().service, "api");
  assert.equal(response.json().version, "test-version");
  await app.close();
});

test("readiness stays degraded before migrations create the database", async () => {
  const dataDir = await fs.mkdtemp(path.join(os.tmpdir(), "docomator-ready-"));
  const app = buildApp(
    loadApiConfig({
      DOCOMATOR_DATA_DIR: dataDir,
      DOCOMATOR_LOG_LEVEL: "fatal"
    })
  );

  const response = await app.inject({ method: "GET", url: "/readyz" });
  assert.equal(response.statusCode, 503);
  assert.equal(response.json().checks.database, "error");
  await app.close();
});

import fs from "node:fs/promises";
import path from "node:path";

import type { ApiConfig } from "@docomator/config";
import type {
  HealthResponse,
  ReadinessResponse,
  SystemInfoResponse
} from "@docomator/contracts";
import Fastify, { type FastifyInstance } from "fastify";

const startedAt = Date.now();

function uptimeSeconds(): number {
  return Math.max(0, Math.floor((Date.now() - startedAt) / 1000));
}

async function pathAccessible(targetPath: string): Promise<boolean> {
  try {
    await fs.access(targetPath);
    return true;
  } catch {
    return false;
  }
}

export function buildApp(config: ApiConfig): FastifyInstance {
  const app = Fastify({
    logger: {
      level: config.logLevel,
      redact: {
        paths: [
          "req.headers.authorization",
          "req.headers.cookie",
          "res.headers.set-cookie"
        ],
        censor: "[REDACTED]"
      }
    }
  });

  app.get("/healthz", async (): Promise<HealthResponse> => ({
    service: "api",
    status: "ok",
    version: config.version,
    timestamp: new Date().toISOString(),
    uptimeSeconds: uptimeSeconds()
  }));

  app.get("/readyz", async (_request, reply): Promise<ReadinessResponse> => {
    const dataDirectoryReady = await pathAccessible(config.dataDir);
    const databaseReady = await pathAccessible(
      path.join(config.dataDir, "docomator.db")
    );
    const ready = dataDirectoryReady && databaseReady;

    if (!ready) {
      reply.code(503);
    }

    return {
      service: "api",
      status: ready ? "ok" : "degraded",
      version: config.version,
      timestamp: new Date().toISOString(),
      uptimeSeconds: uptimeSeconds(),
      checks: {
        dataDirectory: dataDirectoryReady ? "ok" : "error",
        database: databaseReady ? "ok" : "error"
      }
    };
  });

  app.get("/api/v1/system/info", async (): Promise<SystemInfoResponse> => ({
    name: "docomator",
    version: config.version,
    architecture: "modular-monolith",
    runtime: {
      node: process.version,
      platform: process.platform,
      arch: process.arch
    },
    features: {
      offlineFirst: true,
      localLlm: config.llmEnabled,
      documentFormats: ["docx", "xlsx"]
    }
  }));

  return app;
}

import { loadApiConfig } from "@docomator/config";

import { buildApp } from "./app.js";

const config = loadApiConfig();
const app = buildApp(config);

let closing = false;

async function shutdown(signal: NodeJS.Signals): Promise<void> {
  if (closing) {
    return;
  }
  closing = true;
  app.log.info({ signal }, "shutdown requested");

  const timer = setTimeout(() => {
    app.log.error("graceful shutdown timed out");
    process.exit(1);
  }, 10_000);
  timer.unref();

  try {
    await app.close();
    process.exit(0);
  } catch (error) {
    app.log.error({ error }, "graceful shutdown failed");
    process.exit(1);
  }
}

process.once("SIGTERM", () => void shutdown("SIGTERM"));
process.once("SIGINT", () => void shutdown("SIGINT"));

try {
  await app.listen({ host: config.host, port: config.port });
} catch (error) {
  app.log.fatal({ error }, "api failed to start");
  process.exit(1);
}

import assert from "node:assert/strict";
import test from "node:test";

import { runWorkerLoop } from "./loop.js";

test("worker loop stops after abort", async () => {
  const controller = new AbortController();
  let polls = 0;
  let heartbeats = 0;
  let clock = 0;

  await runWorkerLoop({
    pollIntervalMs: 1,
    heartbeatIntervalMs: 10,
    signal: controller.signal,
    now: () => {
      clock += 10;
      return clock;
    },
    onHeartbeat: () => {
      heartbeats += 1;
    },
    onPoll: async () => {
      polls += 1;
      if (polls === 2) {
        controller.abort();
      }
    }
  });

  assert.equal(polls, 2);
  assert.equal(heartbeats, 2);
});

import { setTimeout as sleep } from "node:timers/promises";

export interface WorkerLoopOptions {
  pollIntervalMs: number;
  heartbeatIntervalMs: number;
  signal: AbortSignal;
  onPoll: () => Promise<void>;
  onHeartbeat: () => void;
  now?: () => number;
}

export async function runWorkerLoop(options: WorkerLoopOptions): Promise<void> {
  const now = options.now ?? Date.now;
  let nextHeartbeat = now();

  while (!options.signal.aborted) {
    await options.onPoll();

    const currentTime = now();
    if (currentTime >= nextHeartbeat) {
      options.onHeartbeat();
      nextHeartbeat = currentTime + options.heartbeatIntervalMs;
    }

    try {
      await sleep(options.pollIntervalMs, undefined, { signal: options.signal });
    } catch (error) {
      if (options.signal.aborted) {
        break;
      }
      throw error;
    }
  }
}

import { loadWorkerConfig } from "@docomator/config";

import { runWorkerLoop } from "./loop.js";

const config = loadWorkerConfig();
const controller = new AbortController();

function log(level: "info" | "error", message: string, extra = {}): void {
  process.stdout.write(
    `${JSON.stringify({
      level,
      service: "worker",
      message,
      version: config.version,
      timestamp: new Date().toISOString(),
      ...extra
    })}\n`
  );
}

function stop(signal: NodeJS.Signals): void {
  log("info", "shutdown requested", { signal });
  controller.abort();
}

process.once("SIGTERM", () => stop("SIGTERM"));
process.once("SIGINT", () => stop("SIGINT"));

try {
  log("info", "worker started", {
    pollIntervalMs: config.pollIntervalMs,
    llmEnabled: config.llmEnabled
  });

  await runWorkerLoop({
    pollIntervalMs: config.pollIntervalMs,
    heartbeatIntervalMs: config.heartbeatIntervalMs,
    signal: controller.signal,
    onPoll: async () => {
      // Bootstrap behavior only. Queue claiming and scheduler execution are
      // implemented in the automation milestone described in docs/ROADMAP.md.
    },
    onHeartbeat: () => log("info", "worker heartbeat")
  });

  log("info", "worker stopped");
} catch (error) {
  log("error", "worker failed", {
    error: error instanceof Error ? error.message : String(error)
  });
  process.exitCode = 1;
}
